// // This module is designed to synchronize and select between two data inputs based on the select signal. However, it actually captures the value of 'd' when 'select' is high and 'sd' when 'select' is low.
module top_module(clk ,select, sd, d, q);input clk;
input select;
input sd;
input d;
output reg q;
wire f;


assign f = (select)? sd : d;

always @(negedge clk) begin
    q <= f;
end

endmodule
